import { useEffect, useRef, useState } from 'react';
import { useGameState, useGameActions } from '../../state/store';
import { trapFocus } from '../a11y/trap-focus';
import { renderShareCard, copyShareCard, downloadShareCard } from './share-card';
import './win.css';

interface Props {
  timeMs: number;
  mistakes: number;
  hintsUsed: number;
  isPersonalBest: boolean;
  onClose: () => void;
}

function fmt(ms: number): string {
  const total = Math.floor(ms / 1000);
  const m = Math.floor(total / 60), s = total % 60;
  return `${String(m).padStart(2, '0')}:${String(s).padStart(2, '0')}`;
}

/**
 * Win celebration sheet — shows after a puzzle is solved. Reveals the hidden
 * picture (painted to a canvas) and the player's stats. The "Next puzzle"
 * action triggers a fresh game in the same mode/size.
 *
 * Lazy-loaded by AnimationsSlot so it stays out of the boot bundle.
 *
 * Focus is trapped inside the sheet; Escape dismisses.
 */
export function WinCelebration({ timeMs, mistakes, hintsUsed, isPersonalBest, onClose }: Props) {
  const { board, size, mode } = useGameState();
  const a = useGameActions();
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const sheetRef = useRef<HTMLDivElement>(null);
  const [copied, setCopied] = useState(false);

  const perfect = mistakes === 0 && hintsUsed === 0;

  // Paint the solution picture to a small canvas for the celebration art.
  // Time: O(rows*cols), well under 1 ms even at 20x20.
  useEffect(() => {
    const c = canvasRef.current;
    if (!c) return;
    const dpr = Math.min(2, window.devicePixelRatio || 1);
    const target = 220;
    const cellPx = Math.floor(target / Math.max(board.rows, board.cols));
    const w = cellPx * board.cols;
    const h = cellPx * board.rows;
    c.width = w * dpr; c.height = h * dpr;
    c.style.width = `${w}px`; c.style.height = `${h}px`;
    const ctx = c.getContext('2d');
    if (!ctx) return;
    ctx.scale(dpr, dpr);
    const cs = getComputedStyle(document.documentElement);
    const paper = cs.getPropertyValue('--paper').trim() || '#ffffff';
    const ink = cs.getPropertyValue('--ink').trim() || '#1c1c1e';
    ctx.fillStyle = paper;
    ctx.fillRect(0, 0, w, h);
    ctx.fillStyle = ink;
    for (let r = 0; r < board.rows; r++) {
      for (let col = 0; col < board.cols; col++) {
        if (board.solution[r * board.cols + col] === 1) {
          ctx.fillRect(col * cellPx, r * cellPx, cellPx, cellPx);
        }
      }
    }
  }, [board]);

  // Focus trap + Escape — focus the "Next" CTA, not the first close button.
  useEffect(() => {
    const node = sheetRef.current;
    if (!node) return;
    const release = trapFocus(node);
    const autofocus = node.querySelector<HTMLElement>('[data-autofocus="true"]');
    autofocus?.focus();
    function onKey(e: KeyboardEvent) { if (e.key === 'Escape') onClose(); }
    window.addEventListener('keydown', onKey);
    return () => { release(); window.removeEventListener('keydown', onKey); };
  }, [onClose]);

  async function onCopy() {
    const ok = await copyShareCard({
      board, size, mode, timeMs, mistakes, hintsUsed, perfect, isPersonalBest,
    });
    setCopied(ok);
    if (ok) setTimeout(() => setCopied(false), 1800);
  }

  function onDownload() {
    void renderShareCard({
      board, size, mode, timeMs, mistakes, hintsUsed, perfect, isPersonalBest,
    }).then(url => downloadShareCard(url, `etch-${size}-${Date.now()}.png`));
  }

  function onNext() {
    onClose();
    // After a daily, daily is "done" — drop into free play at the same size so the
    // player can keep solving. After a free game, regenerate at the same size.
    void a.newGame({ mode: 'free', size });
  }

  return (
    <div className="etch-win-backdrop" role="dialog" aria-modal="true" aria-label="Puzzle solved">
      <div className="etch-win-sheet" ref={sheetRef}>
        <div className="etch-win-art">
          <canvas ref={canvasRef} aria-hidden="true" />
          {isPersonalBest && (
            <span className="etch-win-pb-ribbon" aria-label="Personal best">PB</span>
          )}
        </div>
        <h2 className="etch-win-title">{perfect ? 'Perfect!' : 'Solved!'}</h2>
        <p className="etch-win-sub">
          {mode === 'daily' ? 'Daily' : 'Free play'} · {size}
        </p>
        <dl className="etch-win-stats">
          <div>
            <dt>Time</dt>
            <dd className="etch-win-stat-big">{fmt(timeMs)}</dd>
          </div>
          <div>
            <dt>Mistakes</dt>
            <dd>{mistakes}</dd>
          </div>
          <div>
            <dt>Hints</dt>
            <dd>{hintsUsed}</dd>
          </div>
        </dl>
        {perfect && (
          <p className="etch-win-perfect-badge" aria-label="No mistakes, no hints">
            ◆ No mistakes · no hints
          </p>
        )}
        <div className="etch-win-actions">
          <button
            type="button"
            className="etch-win-btn etch-win-btn-ghost"
            onClick={() => void onCopy()}
          >
            {copied ? 'Copied!' : 'Copy share card'}
          </button>
          <button
            type="button"
            className="etch-win-btn etch-win-btn-ghost"
            onClick={onDownload}
          >
            Download PNG
          </button>
          <button
            type="button"
            className="etch-win-btn etch-win-btn-primary"
            onClick={onNext}
            data-autofocus="true"
          >
            Next puzzle
          </button>
        </div>
        <button
          type="button"
          className="etch-win-close"
          aria-label="Close"
          onClick={onClose}
        >
          ×
        </button>
      </div>
    </div>
  );
}

export default WinCelebration;
